const express = require('express');
const axios = require('axios');
const jwt = require('jsonwebtoken');
const session = require('express-session');
const { URLSearchParams } = require('url');

const app = express();
app.use(express.json());
app.use(session({
  secret: process.env.SESSION_SECRET || 'fallback-secret',
  resave: false,
  saveUninitialized: false,
  cookie: { secure: false, httpOnly: true, maxAge: 24 * 60 * 60 * 1000 }
}));

const OIDC_CONFIG = {
  issuer: process.env.OIDC_ISSUER,
  clientId: process.env.OIDC_CLIENT_ID,
  clientSecret: process.env.OIDC_CLIENT_SECRET,
  redirectUri: process.env.OIDC_REDIRECT_URI,
  authorizationEndpoint: `${process.env.OIDC_ISSUER}/oauth2/authorize`,
  tokenEndpoint: `${process.env.OIDC_ISSUER}/oauth2/token`
};

// Step 1: Initial implementation
app.get('/login', (req, res) => {
  const params = new URLSearchParams({
    response_type: 'code',
    client_id: OIDC_CONFIG.clientId,
    redirect_uri: OIDC_CONFIG.redirectUri,
    scope: 'openid profile email',
    state: Math.random().toString(36).substring(2)
  });
  
  res.redirect(`${OIDC_CONFIG.authorizationEndpoint}?${params.toString()}`);
});

app.get('/callback', async (req, res) => {
  const { code, state } = req.query;
  
  if (!code) {
    return res.status(400).send('Authorization code missing');
  }
  
  try {
    // Exchange authorization code for tokens
    const tokenResponse = await axios.post(OIDC_CONFIG.tokenEndpoint, 
      new URLSearchParams({
        grant_type: 'authorization_code',
        client_id: OIDC_CONFIG.clientId,
        client_secret: OIDC_CONFIG.clientSecret,
        redirect_uri: OIDC_CONFIG.redirectUri,
        code: code
      }),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      }
    );
    
    const { id_token, access_token } = tokenResponse.data;
    
    // Decode id_token
    const decodedToken = jwt.decode(id_token);
    
    if (!decodedToken) {
      return res.status(400).send('Invalid ID token');
    }
    
    // Create session
    req.session.user = {
      sub: decodedToken.sub,
      email: decodedToken.email,
      name: decodedToken.name,
      accessToken: access_token
    };
    
    req.session.isAuthenticated = true;
    
    res.redirect('/dashboard');
    
  } catch (error) {
    console.error('Token exchange error:', error);
    res.status(500).send('Authentication failed');
  }
});

app.get('/dashboard', (req, res) => {
  if (!req.session.isAuthenticated) {
    return res.redirect('/login');
  }
  
  res.json({
    message: 'Welcome to dashboard',
    user: req.session.user
  });
});

app.get('/logout', (req, res) => {
  req.session.destroy();
  res.redirect('/login');
});

