app.get('/secure/callback', async (req, res) => {
  const { code, state } = req.query;
  
  if (!code) {
    return res.status(400).send('Authorization code missing');
  }
  
  try {
    // Exchange authorization code for tokens
    const tokenResponse = await axios.post(OIDC_CONFIG.tokenEndpoint, 
      new URLSearchParams({
        grant_type: 'authorization_code',
        client_id: OIDC_CONFIG.clientId,
        client_secret: OIDC_CONFIG.clientSecret,
        redirect_uri: OIDC_CONFIG.redirectUri,
        code: code
      }),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      }
    );
    
    const { id_token, access_token } = tokenResponse.data;
    
    // Validate id_token properly
    const decodedToken = jwt.decode(id_token, { complete: true });
    
    if (!decodedToken || !decodedToken.payload) {
      return res.status(400).send('Invalid ID token structure');
    }
    
    const payload = decodedToken.payload;
    
    // Validate required claims
    if (!payload.sub || !payload.iss || !payload.aud) {
      return res.status(400).send('Missing required claims in ID token');
    }
    
    // Validate issuer
    if (payload.iss !== OIDC_CONFIG.issuer) {
      return res.status(400).send('Invalid token issuer');
    }
    
    // Validate audience
    if (Array.isArray(payload.aud)) {
      if (!payload.aud.includes(OIDC_CONFIG.clientId)) {
        return res.status(400).send('Invalid token audience');
      }
    } else if (payload.aud !== OIDC_CONFIG.clientId) {
      return res.status(400).send('Invalid token audience');
    }
    
    // Validate expiration
    const currentTime = Math.floor(Date.now() / 1000);
    if (payload.exp && payload.exp < currentTime) {
      return res.status(400).send('Token has expired');
    }
    
    // Validate not before
    if (payload.nbf && payload.nbf > currentTime) {
      return res.status(400).send('Token not yet valid');
    }
    
    // Create session with validated claims
    req.session.user = {
      sub: payload.sub,
      email: payload.email,
      name: payload.name,
      accessToken: access_token,
      tokenIssuedAt: payload.iat,
      tokenExpiresAt: payload.exp
    };
    
    req.session.isAuthenticated = true;
    
    res.redirect('/secure/dashboard');
    
  } catch (error) {
    console.error('Token exchange error:', error);
    res.status(500).send('Authentication failed');
  }
});

